//! # Ï„-bowl speculative-precision dequant at the LIVE lm_head seam (GATED).
//!
//! This is the operational wiring of the `2Ï„ â‰¤ Î³` energy gate
//! ([`crate::tukey_bowl::gate_energy`], the runtime twin of
//! `Gnosis.QualityMarginCacheAdmissibility` / `EnergyMarginBridgeAdmissibility`)
//! into the live forward path that turns stored quantized lm_head rows into the
//! logits whose argmax is the next token.
//!
//! ## Safety contract (why this can never flip a token)
//!
//! The gate is wired as an **observer that never mutates the served logits**.
//! `compute_lm_head_logits` always computes the TRUE full-precision logits and
//! takes the argmax over THEM â€” exactly as today. When the flag
//! `TAU_BOWL_DEQUANT_ENABLED` is set, we ALSO, per row `v`:
//!
//!   1. re-quantize the lm_head row to a coarse code C (fewer bits than the
//!      stored Q8_0/Q4_K), and measure the in-row residual `â€–Ï„_vâ€–â‚‚`;
//!   2. energy-gate it against the LIVE decision margin
//!      `Î³ = top1_logit âˆ’ top2_logit` of the true logits, folding in the
//!      hidden-state energy `â€–hâ€–â‚‚`: admit row `v` iff `2Â·(â€–Ï„_vâ€–â‚‚Â·â€–hâ€–â‚‚) â‰¤ Î³`.
//!
//! Admitted rows are CERTIFIED (the cert: `2Ï„ â‰¤ Î³ â‡’ argmax preserved`) to carry
//! the coarse code without changing the argmax; missed rows keep full precision
//! ("miss, not lie"). Because the served logits are the full-precision ones
//! either way, **the token is byte-identical to the flag-off path** â€” the gate's
//! job here is to MEASURE how much of the lm_head could run at the coarse code
//! at the real per-step margin, i.e. the certified resident-bit reduction.
//!
//! When the flag is OFF this module is never entered; the lm_head path is the
//! verbatim pre-existing one.

#![allow(dead_code)]

use crate::e8_quantizer::nearest_e8;
use crate::tukey_bowl::{gate_energy, Admission};

/// Is the gated speculative-precision dequant path enabled? DEFAULT FALSE.
/// Enabled only when `TAU_BOWL_DEQUANT_ENABLED` is set to `1`/`true`/`on`/`yes`.
#[inline]
pub fn enabled() -> bool {
    match std::env::var("TAU_BOWL_DEQUANT_ENABLED") {
        Ok(v) => {
            let v = v.trim().to_ascii_lowercase();
            v == "1" || v == "true" || v == "on" || v == "yes"
        }
        Err(_) => false,
    }
}

/// Is the *substitution* probe enabled? When set (in ADDITION to
/// `TAU_BOWL_DEQUANT_ENABLED`), admitted rows are recomputed at the coarse code
/// and the SUBSTITUTED argmax is recorded in the report so the safety harness can
/// detect a real argmax flip. DEFAULT FALSE. The served logits are NEVER mutated
/// by this â€” it only populates `GateStepReport::substituted_argmax`. Independent
/// of the served path so the measurement can never degrade output.
#[inline]
pub fn substitute_enabled() -> bool {
    match std::env::var("TAU_BOWL_DEQUANT_SUBSTITUTE") {
        Ok(v) => {
            let v = v.trim().to_ascii_lowercase();
            v == "1" || v == "true" || v == "on" || v == "yes"
        }
        Err(_) => false,
    }
}

/// Should the substitution be driven by the EXACT per-logit gate (sound, admits
/// ~half the lm_head here) instead of the conservative Cauchyâ€“Schwarz gate (which
/// admits ~nothing)? `TAU_BOWL_DEQUANT_EXACT`, DEFAULT FALSE. Only meaningful when
/// `TAU_BOWL_DEQUANT_SUBSTITUTE` is also on. Both gates are sound; this only
/// changes which rows actually carry the coarse code in the no-flip measurement.
#[inline]
pub fn exact_substitute_enabled() -> bool {
    match std::env::var("TAU_BOWL_DEQUANT_EXACT") {
        Ok(v) => {
            let v = v.trim().to_ascii_lowercase();
            v == "1" || v == "true" || v == "on" || v == "yes"
        }
        Err(_) => false,
    }
}

/// Coarse code budget, in bits/weight, to speculate the lm_head down to.
/// From `TAU_BOWL_DEQUANT_BITS` (default 5 â€” the bowl-footprint E8-5b winner).
#[inline]
pub fn coarse_bits() -> u32 {
    std::env::var("TAU_BOWL_DEQUANT_BITS")
        .ok()
        .and_then(|s| s.trim().parse::<u32>().ok())
        .filter(|&b| (1..8).contains(&b))
        .unwrap_or(5)
}

/// Which coarse lattice to draft with. E_8 (default) gives a lower L2 residual
/// at the same bit budget than cubic (the certified ~14% covering edge).
#[derive(Clone, Copy, Debug, PartialEq)]
pub enum CoarseLattice {
    Cubic,
    E8,
}

#[inline]
pub fn coarse_lattice() -> CoarseLattice {
    match std::env::var("TAU_BOWL_DEQUANT_LATTICE")
        .ok()
        .map(|s| s.trim().to_ascii_lowercase())
        .as_deref()
    {
        Some("cubic") => CoarseLattice::Cubic,
        _ => CoarseLattice::E8,
    }
}

/// Re-quantize one full-precision row to `bits` levels over its own symmetric
/// range `[-A, A]` (A = max|centered w|), at the chosen lattice, and return the
/// L2 norm of the residual `â€–w_centered âˆ’ C(w_centered)â€–â‚‚`. Mirrors the
/// `bowl-footprint` code exactly so the measured Ï„ matches the calibrated bin.
pub fn row_residual_l2(lattice: CoarseLattice, bits: u32, row: &[f32]) -> f64 {
    let d = row.len();
    if d == 0 {
        return 0.0;
    }
    let mean = row.iter().copied().sum::<f32>() / d as f32;
    let mut c = vec![0.0f32; d];
    let mut a = 0.0f64;
    for i in 0..d {
        c[i] = row[i] - mean;
        a = a.max(c[i].abs() as f64);
    }
    let levels = (1u64 << bits) as f64;
    let step = if a <= 0.0 || levels <= 1.0 {
        1e-9
    } else {
        2.0 * a / (levels - 1.0)
    } as f32;

    let mut q = vec![0.0f32; d];
    match lattice {
        CoarseLattice::Cubic => {
            let inv = 1.0_f32 / step;
            for i in 0..d {
                q[i] = (c[i] * inv).round() * step;
            }
        }
        CoarseLattice::E8 => {
            let blocks = d / 8;
            for b in 0..blocks {
                let base = b * 8;
                let mut scaled = [0.0_f64; 8];
                for k in 0..8 {
                    scaled[k] = c[base + k] as f64 * (2.0 / step as f64);
                }
                let qc = nearest_e8(scaled);
                for k in 0..8 {
                    q[base + k] = ((qc[k] as f64) * (step as f64 / 2.0)) as f32;
                }
            }
            // cubic on the d % 8 tail (cannot form an E_8 cell)
            let inv = 1.0_f32 / step;
            for i in (blocks * 8)..d {
                q[i] = (c[i] * inv).round() * step;
            }
        }
    }
    let mut s = 0.0f64;
    for i in 0..d {
        let e = (c[i] - q[i]) as f64;
        s += e * e;
    }
    s.sqrt()
}

/// Reconstruct one full-precision row at the coarse code: re-quantize the
/// centered row to `bits` levels over its own symmetric range at `lattice`, then
/// add the per-row mean back so the result is a faithful coarse approximation of
/// the ORIGINAL (un-centered) weights. `out` is filled with that approximation.
/// This is the substitution that an admitted row would actually carry into the
/// matvec; `â€–row âˆ’ outâ€–â‚‚ = â€–centered âˆ’ C(centered)â€–â‚‚` is exactly the Ï„ measured
/// by [`row_residual_l2`] (the mean cancels), so the gate's Ï„ matches the swap.
pub fn coarse_reconstruct_row(lattice: CoarseLattice, bits: u32, row: &[f32], out: &mut Vec<f32>) {
    let d = row.len();
    out.resize(d, 0.0);
    if d == 0 {
        return;
    }
    let mean = row.iter().copied().sum::<f32>() / d as f32;
    let mut c = vec![0.0f32; d];
    let mut a = 0.0f64;
    for i in 0..d {
        c[i] = row[i] - mean;
        a = a.max(c[i].abs() as f64);
    }
    let levels = (1u64 << bits) as f64;
    let step = if a <= 0.0 || levels <= 1.0 {
        1e-9
    } else {
        2.0 * a / (levels - 1.0)
    } as f32;
    match lattice {
        CoarseLattice::Cubic => {
            let inv = 1.0_f32 / step;
            for i in 0..d {
                out[i] = (c[i] * inv).round() * step + mean;
            }
        }
        CoarseLattice::E8 => {
            let blocks = d / 8;
            for b in 0..blocks {
                let base = b * 8;
                let mut scaled = [0.0_f64; 8];
                for k in 0..8 {
                    scaled[k] = c[base + k] as f64 * (2.0 / step as f64);
                }
                let qc = nearest_e8(scaled);
                for k in 0..8 {
                    out[base + k] = ((qc[k] as f64) * (step as f64 / 2.0)) as f32 + mean;
                }
            }
            let inv = 1.0_f32 / step;
            for i in (blocks * 8)..d {
                out[i] = (c[i] * inv).round() * step + mean;
            }
        }
    }
}

/// One gated decode step's measurement over the lm_head rows.
#[derive(Clone, Copy, Debug, Default)]
pub struct GateStepReport {
    /// Rows gated (â‰ˆ vocab_size for full lm_head; the sampled cap otherwise).
    pub rows: usize,
    /// Rows the energy gate ADMITTED at the coarse code (certified no-flip).
    pub admitted: usize,
    /// The live decision margin Î³ = top1 âˆ’ top2 of the TRUE logits.
    pub gamma: f64,
    /// â€–hâ€–â‚‚, the post-RMSNorm hidden-state energy folded into the gate.
    pub h_energy: f64,
    /// Coarse-code bits/weight under test.
    pub coarse_bits: f64,
    /// Stored baseline bits/weight (the qtype actually resident).
    pub baseline_bits: f64,
    /// Mean per-row scaled residual `â€–Ï„_vâ€–â‚‚Â·â€–hâ€–â‚‚` over gated rows.
    pub mean_scaled_tau: f64,
    /// Worst scaled residual among ADMITTED rows (must satisfy 2Â·s â‰¤ Î³).
    pub max_admitted_scaled_tau: f64,
    /// Argmax over the TRUE full-precision logits (the served token id).
    pub true_argmax: u32,
    /// Argmax over the SUBSTITUTED logits: admitted rows recomputed with the
    /// coarse code, missed rows kept full-precision ("miss, not lie"). This is
    /// the genuine no-flip test â€” if the gate is sound it MUST equal
    /// `true_argmax` (the cert `2Ï„ â‰¤ Î³ â‡’ argmax preserved`). `u32::MAX` when the
    /// substitution was not computed (gate disabled / not on the substitute path).
    pub substituted_argmax: u32,
    /// Whether the substituted argmax was actually computed this step.
    pub substitution_checked: bool,
    /// DIAGNOSTIC (only when substituting): rows that would admit under a TIGHTER
    /// but still-sound gate that uses the EXACT per-logit perturbation
    /// `|âŸ¨h, w_v âˆ’ C(w_v)âŸ©|` instead of the loose Cauchyâ€“Schwarz bound
    /// `â€–Ï„_vâ€–â‚‚Â·â€–hâ€–â‚‚`. This quantifies how much of the 0%-admit is Câ€“S slack vs a
    /// genuinely too-coarse code. NOT used to admit anything here â€” purely an
    /// honest measurement of headroom for a future exact-perturbation gate.
    pub exact_gate_admitted: usize,
    /// DIAGNOSTIC: worst EXACT per-logit perturbation over the gated rows
    /// (max |âŸ¨h, Ï„_vâŸ©|). Compare to Î³/2: rows with this â‰¤ Î³/2 are exactly-safe.
    pub max_exact_delta: f64,
}

impl GateStepReport {
    #[inline]
    pub fn admit_frac(&self) -> f64 {
        if self.rows == 0 {
            0.0
        } else {
            self.admitted as f64 / self.rows as f64
        }
    }
    /// Certified resident bits/weight = coarseÂ·admit + baselineÂ·(1âˆ’admit).
    #[inline]
    pub fn certified_bits_per_weight(&self) -> f64 {
        let f = self.admit_frac();
        self.coarse_bits * f + self.baseline_bits * (1.0 - f)
    }
    /// Saved fraction vs the resident baseline (0 when nothing admits).
    #[inline]
    pub fn saved_fraction(&self) -> f64 {
        if self.baseline_bits <= 0.0 {
            0.0
        } else {
            1.0 - self.certified_bits_per_weight() / self.baseline_bits
        }
    }
}

/// Gate every lm_head row at the live margin. `truth_rows` are the
/// full-precision (dequantized) lm_head rows; `h` is the post-RMSNorm hidden
/// state for the current token; `gamma` is the TRUE top1âˆ’top2 logit gap.
///
/// This DOES NOT modify any logit â€” it only measures the certified admit rate
/// (and thus the resident-bit reduction) for this step. The caller serves the
/// full-precision argmax unchanged.
pub fn gate_step<F>(
    get_row: F,
    rows: usize,
    h: &[f32],
    gamma: f64,
    lattice: CoarseLattice,
    bits: u32,
    baseline_bits: f64,
) -> GateStepReport
where
    F: Fn(usize, &mut Vec<f32>),
{
    gate_step_substitute(get_row, rows, h, gamma, lattice, bits, baseline_bits, None)
}

/// Like [`gate_step`], but when `true_logits` is `Some(logits)` ALSO computes the
/// **substituted argmax**: for each ADMITTED row, recompute its logit from the
/// coarse-code-reconstructed weights (`âŸ¨h, C(w_v)âŸ©`); for each MISSED row keep
/// the supplied true logit. The argmax over this substituted logit vector is the
/// genuine no-flip test â€” under a sound gate it must equal the true argmax. This
/// NEVER touches the caller's served logits; the substituted argmax is recorded
/// in the report for the safety harness only.
///
/// Substitution is only attempted over the first `rows` entries; rows beyond the
/// sampled cap keep their true logit, so a capped run is a conservative subset
/// (it can only HIDE a flip that a full run would surface â€” the harness reports
/// the cap honestly and the SHIP verdict requires a full-vocab run).
#[allow(clippy::too_many_arguments)]
pub fn gate_step_substitute<F>(
    get_row: F,
    rows: usize,
    h: &[f32],
    gamma: f64,
    lattice: CoarseLattice,
    bits: u32,
    baseline_bits: f64,
    true_logits: Option<&[f32]>,
) -> GateStepReport
where
    F: Fn(usize, &mut Vec<f32>),
{
    gate_step_substitute_mode(
        get_row,
        rows,
        h,
        gamma,
        lattice,
        bits,
        baseline_bits,
        true_logits,
        false,
    )
}

/// Like [`gate_step_substitute`], but `exact_mode` selects WHICH sound gate
/// actually drives the substitution into the shadow logits:
///   * `false` (default): the shipped Cauchyâ€“Schwarz energy gate
///     (`2Â·â€–Ï„â€–â‚‚Â·â€–hâ€–â‚‚ â‰¤ Î³`) â€” conservative; on this knot it admits ~nothing.
///   * `true`: the EXACT per-logit gate (`2Â·|âŸ¨h,Ï„âŸ©| â‰¤ Î³`) â€” also sound (it uses
///     the measured perturbation, not an estimate), and admits ~half the rows.
/// Either way the substituted argmax is recorded for the no-flip harness; the
/// caller's served logits are never touched. `exact_mode=true` makes the no-flip
/// test NON-VACUOUS (it actually swaps the admitted rows' logits).
#[allow(clippy::too_many_arguments)]
pub fn gate_step_substitute_mode<F>(
    get_row: F,
    rows: usize,
    h: &[f32],
    gamma: f64,
    lattice: CoarseLattice,
    bits: u32,
    baseline_bits: f64,
    true_logits: Option<&[f32]>,
    exact_mode: bool,
) -> GateStepReport
where
    F: Fn(usize, &mut Vec<f32>),
{
    let h_energy = h.iter().map(|&x| (x as f64) * (x as f64)).sum::<f64>().sqrt();
    let mut rep = GateStepReport {
        rows,
        gamma,
        h_energy,
        coarse_bits: bits as f64,
        baseline_bits,
        substituted_argmax: u32::MAX,
        ..Default::default()
    };

    // The substituted-logit vector (only materialized when we have true logits to
    // seed the missed rows). Starts as a copy of the true logits so MISSED rows
    // and rows beyond `rows` already hold the full-precision value.
    let mut subst: Option<Vec<f32>> = true_logits.map(|t| {
        rep.substitution_checked = true;
        // true argmax over the full true-logit vector.
        rep.true_argmax = argmax_u32(t);
        t.to_vec()
    });

    if !(gamma > 0.0 && gamma.is_finite()) || rows == 0 {
        // no margin â‡’ nothing safely maskable; substituted == true everywhere.
        if let Some(s) = &subst {
            rep.substituted_argmax = argmax_u32(s);
        }
        return rep;
    }

    let half_margin = gamma * 0.5;
    let mut scaled_acc = 0.0f64;
    let mut row_buf: Vec<f32> = Vec::new();
    let mut coarse_buf: Vec<f32> = Vec::new();
    for v in 0..rows {
        get_row(v, &mut row_buf);
        let tau = row_residual_l2(lattice, bits, &row_buf);
        let scaled = tau * h_energy; // âŸ¨Ï„,hâŸ© â‰¤ â€–Ï„â€–â‚‚Â·â€–hâ€–â‚‚ (Cauchyâ€“Schwarz)
        scaled_acc += scaled;

        // EXACT per-logit perturbation diagnostic: needs the coarse row. Only
        // computed when substituting (we have h and true logits to compare).
        if subst.is_some() {
            coarse_reconstruct_row(lattice, bits, &row_buf, &mut coarse_buf);
            let mut coarse_logit = 0.0f64;
            let mut exact_delta = 0.0f64;
            let n = h.len().min(coarse_buf.len());
            for i in 0..n {
                let hi = h[i] as f64;
                coarse_logit += hi * coarse_buf[i] as f64;
                exact_delta += hi * (row_buf[i] - coarse_buf[i]) as f64;
            }
            let exact_abs = exact_delta.abs();
            if exact_abs > rep.max_exact_delta {
                rep.max_exact_delta = exact_abs;
            }
            // Tighter (still sound) gate: admit iff the EXACT perturbation â‰¤ Î³/2.
            let exact_admit = exact_abs <= half_margin;
            if exact_admit {
                rep.exact_gate_admitted += 1;
            }
            // Câ€“S (shipped, conservative) gate admit.
            let cs_admit = matches!(gate_energy(scaled, gamma), Admission::Admit { .. });
            if cs_admit {
                rep.admitted += 1;
                if scaled > rep.max_admitted_scaled_tau {
                    rep.max_admitted_scaled_tau = scaled;
                }
            }
            // WHICH gate drives the real swap into the shadow logits. Both are
            // sound; exact_mode makes the no-flip test non-vacuous.
            let do_swap = if exact_mode { exact_admit } else { cs_admit };
            if do_swap {
                if let Some(s) = &mut subst {
                    s[v] = coarse_logit as f32;
                }
            }
            // NOT swapped â‡’ s[v] stays the true logit (already seeded) â€” miss, not lie.
        } else if let Admission::Admit { .. } = gate_energy(scaled, gamma) {
            // Observe-only path (no substitution): just count the Câ€“S admits.
            rep.admitted += 1;
            if scaled > rep.max_admitted_scaled_tau {
                rep.max_admitted_scaled_tau = scaled;
            }
        }
    }
    rep.mean_scaled_tau = scaled_acc / rows as f64;
    if let Some(s) = &subst {
        rep.substituted_argmax = argmax_u32(s);
    }
    let _ = &mut subst; // (subst dropped here; only its argmax is kept)
    rep
}

/// Argmax over a logit vector (first max wins on ties â€” matches the decode loop).
#[inline]
fn argmax_u32(logits: &[f32]) -> u32 {
    let mut best = 0u32;
    let mut best_val = f32::NEG_INFINITY;
    for (i, &v) in logits.iter().enumerate() {
        if v > best_val {
            best_val = v;
            best = i as u32;
        }
    }
    best
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn disabled_by_default() {
        // The harness runner sets this explicitly; absent the var the gate is off.
        std::env::remove_var("TAU_BOWL_DEQUANT_ENABLED");
        assert!(!enabled(), "must default OFF");
    }

    #[test]
    fn coarse_bits_default_is_five() {
        std::env::remove_var("TAU_BOWL_DEQUANT_BITS");
        assert_eq!(coarse_bits(), 5);
    }

    #[test]
    fn zero_margin_admits_nothing() {
        let h = vec![0.1f32; 16];
        let rep = gate_step(
            |_v, out| {
                out.clear();
                out.extend_from_slice(&[0.0f32; 16]);
            },
            8,
            &h,
            0.0, // no margin
            CoarseLattice::E8,
            5,
            8.0,
        );
        assert_eq!(rep.admitted, 0, "no margin â‡’ no admit (miss, not lie)");
        assert_eq!(rep.admit_frac(), 0.0);
        assert_eq!(rep.certified_bits_per_weight(), 8.0, "all rows stay baseline");
    }

    #[test]
    fn tiny_residual_roomy_margin_admits_and_saves() {
        // Rows that are exactly representable at the coarse grid â‡’ Ï„â‰ˆ0 â‡’ admit.
        // Use a row that is a clean multiple of the cubic step so requant is exact.
        let row: Vec<f32> = (0..16).map(|i| (i as f32 - 8.0) * 0.0).collect(); // all zero
        let h = vec![0.05f32; 16];
        let rep = gate_step(
            |_v, out| {
                out.clear();
                out.extend_from_slice(&row);
            },
            32,
            &h,
            10.0, // roomy margin
            CoarseLattice::Cubic,
            5,
            8.0,
        );
        assert_eq!(rep.admitted, 32, "zero-residual rows all admit under a roomy margin");
        assert!(rep.saved_fraction() > 0.0, "admits â‡’ resident bits drop below baseline");
        assert!(
            2.0 * rep.max_admitted_scaled_tau <= rep.gamma + 1e-9,
            "every admitted row honours 2Â·(Ï„Â·â€–hâ€–) â‰¤ Î³"
        );
    }

    #[test]
    fn substitution_preserves_argmax_when_admitted() {
        // Build a tiny lm_head: 4 rows Ã— 8 dims. Row 2 is the clear winner. Use
        // a roomy margin so rows admit; substituting the coarse code must NOT
        // move the argmax off row 2 (the cert's no-flip guarantee, measured).
        let h: Vec<f32> = vec![0.3, -0.1, 0.2, 0.05, -0.2, 0.1, 0.0, 0.15];
        let rows_data: Vec<Vec<f32>> = vec![
            vec![0.10, 0.02, -0.05, 0.01, 0.03, -0.02, 0.04, 0.00], // row0
            vec![-0.08, 0.05, 0.02, -0.03, 0.01, 0.06, -0.04, 0.02], // row1
            vec![0.40, -0.20, 0.35, 0.10, -0.25, 0.18, 0.05, 0.22], // row2 (winner)
            vec![0.05, 0.01, 0.03, -0.02, 0.00, 0.04, -0.01, 0.02], // row3
        ];
        // True logits = âŸ¨h, rowâŸ©.
        let true_logits: Vec<f32> = rows_data
            .iter()
            .map(|r| h.iter().zip(r).map(|(a, b)| a * b).sum())
            .collect();
        let true_am = true_logits
            .iter()
            .enumerate()
            .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
            .unwrap()
            .0 as u32;
        assert_eq!(true_am, 2, "row2 is the true winner");

        let rep = gate_step_substitute(
            |v, out| {
                out.clear();
                out.extend_from_slice(&rows_data[v]);
            },
            4,
            &h,
            5.0, // roomy margin â‡’ rows admit
            CoarseLattice::E8,
            5,
            8.0,
            Some(&true_logits),
        );
        assert!(rep.substitution_checked, "substitution must have run");
        assert_eq!(rep.true_argmax, true_am, "report records the true argmax");
        // The substituted argmax MUST equal the true argmax (no flip) â€” the
        // measured statement of the QualityMarginCacheAdmissibility cert.
        assert_eq!(
            rep.substituted_argmax, rep.true_argmax,
            "admitted coarse-code substitution must not flip the argmax"
        );
    }

    #[test]
    fn substitution_off_by_default_records_nothing() {
        // gate_step (the non-substitute alias) must leave the argmax unrecorded.
        let h = vec![0.1f32; 8];
        let rep = gate_step(
            |_v, out| {
                out.clear();
                out.extend_from_slice(&[0.0f32; 8]);
            },
            4,
            &h,
            1.0,
            CoarseLattice::E8,
            5,
            8.0,
        );
        assert!(!rep.substitution_checked, "no substitution without true logits");
        assert_eq!(rep.substituted_argmax, u32::MAX, "sentinel = not computed");
    }

    #[test]
    fn nonzero_residual_tight_margin_all_miss() {
        // A row with a genuine in-cell residual (values land BETWEEN grid
        // levels) at a near-zero margin â‡’ every row must miss, never lie.
        // 17 dims with irrational-ish spacing so the 3-bit cubic grid can't
        // represent them exactly â‡’ Ï„ > 0.
        let row: Vec<f32> = (0..17)
            .map(|i| (i as f32 * 0.37).sin() * 0.913 + 0.041)
            .collect();
        // sanity: this row really does have a non-trivial residual at 3 bits.
        assert!(
            row_residual_l2(CoarseLattice::Cubic, 3, &row) > 1e-3,
            "test row must have a real residual to exercise the miss path"
        );
        let h = vec![1.0f32; 17];
        let rep = gate_step(
            |_v, out| {
                out.clear();
                out.extend_from_slice(&row);
            },
            16,
            &h,
            1e-9, // basically no room
            CoarseLattice::Cubic,
            3,
            8.0,
        );
        assert_eq!(rep.admitted, 0, "tight margin â‡’ all miss");
        assert_eq!(rep.certified_bits_per_weight(), 8.0);
    }
}
